                    }
                };

                try
                {
                    ReplaceVisibleMovies(window, pagedMovies);
                    window.MainVM.DbInfo.DBFullPath = $"fixture-defaultlist-append-{Guid.NewGuid():N}.wb";
                    window.MainVM.DbInfo.DBName = "fixture-defaultlist-append";
