                    window.MainVM.DbInfo.DBFullPath = dbPath;
                    window.MainVM.DbInfo.DBName = Path.GetFileNameWithoutExtension(dbPath);
                    window.MainVM.DbInfo.ThumbFolder = thumbFolderPath;

