                          if (wb && typeof wb.onSkinEnter === 'function') {
                            wb.onSkinEnter();
                          }
                          await wb.update();
                          return true;
                        })();
                        """
                    );
                    await WaitForWebConditionAsync(
                        webView,
                        """
                        Array.from(document.querySelectorAll('#view div[id^="thum"]'))
                          .map(x => (x.id || '').trim())
                          .filter(x => /^thum\d+$/.test(x))
                          .length >= 3
                        """,
