            @"E:\clip\gamma.mkv",
            "00:03:45",
            8192,
            18,
            "idol"
        );

        try
        {
            await RunOnStaDispatcherAsync<object?>(async () =>
            {
                using TestEnvironmentScope scope = TestEnvironmentScope.Create();
